I finally went with something similar to Stefan's answer.  I created a module using hook_views_pre_render that checks the correct table against the node id to see if there are any related nodes.  The code is shown below.

&lt;?php

/**
 * Implementation of hook_views_pre_render()
 */
function gretna_views_pre_render(&amp;$view) {
    // Select the right view
    if ($view-&gt;name == 'stores_list') {
        // Check how many results there are
        $count = count($view-&gt;result);
        // For each result (reason we don't use foreach is every result is duplicated twice)
        for($i = 0; $i &lt; $count; $i++) {
            // Get the nid for this row
            $nid = $view-&gt;result[$i]-&gt;nid;
            // Check to see if the node has any related offers
            $result = db_query("SELECT nid FROM {content_type_store_offers} WHERE field_offer_store_nid = %d", $nid);
            $result = db_fetch_array($result);
            // If not false, the row has offers
            if ($result !== FALSE) {
                $view-&gt;result[$i]-&gt;users_uid = "Yes";
            }
            // Else it doesn't
            else {
                $view-&gt;result[$i]-&gt;users_uid = "No";
            }
        }
    }
}

In order to achieve this you need to override the block that displays the product grid in the category edit screen. This block is Mage_Adminhtml_Block_Catalog_Category_Tab_Product.
For this, create a new module. Let's call it Easylife_Adminhtml with the following files:
app/etc/modules/Easylife_Adminhtml.xml - the module declaration file.

&lt;?xml version="1.0"?&gt;
&lt;config&gt;
    &lt;modules&gt;
        &lt;Easylife_Adminhtml&gt;
            &lt;active&gt;true&lt;/active&gt;
            &lt;codePool&gt;local&lt;/codePool&gt;
            &lt;depends&gt;
                &lt;Mage_Adminhtml /&gt;
            &lt;/depends&gt;
        &lt;/Easylife_Adminhtml&gt;
    &lt;/modules&gt;
&lt;/config&gt;


app/code/local/Easylife/Adminhtml/etc/config.xml - the module configuration file

&lt;?xml version="1.0"?&gt;
&lt;config&gt;
    &lt;modules&gt;
        &lt;Easylife_Adminhtml&gt;
            &lt;version&gt;0.0.1&lt;/version&gt;
        &lt;/Easylife_Adminhtml&gt;
    &lt;/modules&gt;
    &lt;global&gt;
        &lt;blocks&gt;
            &lt;adminhtml&gt;
                &lt;rewrite&gt;
                    &lt;catalog_category_tab_product&gt;Easylife_Adminhtml_Block_Catalog_Category_Tab_Product&lt;/catalog_category_tab_product&gt;&lt;!-- override the default block with your ownw--&gt;
                &lt;/rewrite&gt;
            &lt;/adminhtml&gt;
        &lt;/blocks&gt;
    &lt;/global&gt;
&lt;/config&gt;


app/code/local/Easylife/Adminhtml/Block/Catalog/Category/Tab/Product.php - the block override class.

&lt;?php 
class Easylife_Adminhtml_Block_Catalog_Category_Tab_Product extends Mage_Adminhtml_Block_Catalog_Category_Tab_Product{
    protected function _prepareCollection()
    {
        if ($this-&gt;getCategory()-&gt;getId()) {
            $this-&gt;setDefaultFilter(array('in_category'=&gt;1));
        }
        $collection = Mage::getModel('catalog/product')-&gt;getCollection()
            -&gt;addAttributeToSelect('name')
            -&gt;addAttributeToSelect('sku')
            -&gt;addAttributeToSelect('price')
            -&gt;addAttributeToSelect('special_price')//add attributes you need
            -&gt;addStoreFilter($this-&gt;getRequest()-&gt;getParam('store'))
            -&gt;joinField('position',
                'catalog/category_product',
                'position',
                'product_id=entity_id',
                'category_id='.(int) $this-&gt;getRequest()-&gt;getParam('id', 0),
                'left');
        $this-&gt;setCollection($collection);

        if ($this-&gt;getCategory()-&gt;getProductsReadonly()) {
            $productIds = $this-&gt;_getSelectedProducts();
            if (empty($productIds)) {
                $productIds = 0;
            }
            $this-&gt;getCollection()-&gt;addFieldToFilter('entity_id', array('in'=&gt;$productIds));
        }

        //simulate parent::parent::_prepareCollection() because you cannot call parent::_prepareCollection
        if ($this-&gt;getCollection()) {

            $this-&gt;_preparePage();

            $columnId = $this-&gt;getParam($this-&gt;getVarNameSort(), $this-&gt;_defaultSort);
            $dir      = $this-&gt;getParam($this-&gt;getVarNameDir(), $this-&gt;_defaultDir);
            $filter   = $this-&gt;getParam($this-&gt;getVarNameFilter(), null);

            if (is_null($filter)) {
                $filter = $this-&gt;_defaultFilter;
            }

            if (is_string($filter)) {
                $data = $this-&gt;helper('adminhtml')-&gt;prepareFilterString($filter);
                $this-&gt;_setFilterValues($data);
            }
            else if ($filter &amp;&amp; is_array($filter)) {
                $this-&gt;_setFilterValues($filter);
            }
            else if(0 !== sizeof($this-&gt;_defaultFilter)) {
                $this-&gt;_setFilterValues($this-&gt;_defaultFilter);
            }

            if (isset($this-&gt;_columns[$columnId]) &amp;&amp; $this-&gt;_columns[$columnId]-&gt;getIndex()) {
                $dir = (strtolower($dir)=='desc') ? 'desc' : 'asc';
                $this-&gt;_columns[$columnId]-&gt;setDir($dir);
                $this-&gt;_setCollectionOrder($this-&gt;_columns[$columnId]);
            }

            if (!$this-&gt;_isExport) {
                $this-&gt;getCollection()-&gt;load();
                $this-&gt;_afterLoadCollection();
            }
        }

        return $this;
    }

    protected function _prepareColumns()
    {
        //add the special price collumn after the 'price' column
        $this-&gt;addColumnAfter('special_price', array(
            'header'    =&gt; Mage::helper('catalog')-&gt;__('Special Price'),
            'type'  =&gt; 'currency',
            'width'     =&gt; '1',
            'currency_code' =&gt; (string) Mage::getStoreConfig(Mage_Directory_Model_Currency::XML_PATH_CURRENCY_BASE),
            'index'     =&gt; 'special_price'
        ), 'price');
        return parent::_prepareColumns();
    }
}


